// ── Generator function ──
function generateServiceAnimalPage(
  template: ServiceTemplate,
  animal: AnimalProfile,
  allValidSlugs: Set<string>
): ServiceAnimalPage {
  const slug = `${template.slugPrefix}-${animal.id}`;
  const relatedSlugs = template.relatedPrefix
    .map((p) => `${p}-${animal.id}`)
    .filter((s) => s !== slug && allValidSlugs.has(s));

  // Get animal-specific facts if available
  const specificFacts = animal.specificFacts[template.slugPrefix] || [];

  // Merge specific facts into whatIncludes
  const whatIncludes = specificFacts.length > 0
    ? [...specificFacts, ...template.defaultWhatIncludes.slice(specificFacts.length)]
    : template.defaultWhatIncludes;

  return {
    slug,
    serviceSlug: template.serviceSlug,
    animalId: animal.id,
    animalName: animal.name,
    animalEmoji: animal.emoji,
    serviceName: template.serviceName,
    metaTitle: template.metaTitleTemplate(animal.name),
    metaDescription: template.metaDescTemplate(animal.name),
    h1: template.h1Template(animal.name),
    answerSummary: template.answerTemplate(animal.name, animal.species),
    quickFacts: template.defaultQuickFacts(animal.name, animal.emoji),
    intro: template.introTemplate(animal.name, animal.species),
    whatIncludes,
    whenToDo: template.defaultWhenToDo,
    warningSignsTitle: template.warningSignsTitle,
    warningSigns: template.defaultWarningSigns,
    ageGuidance: template.defaultAgeGuidance(animal.youngName, animal.seniorAge),
    costRange: template.costRange,
    faq: template.defaultFaq(animal.name),
    relatedServiceAnimals: relatedSlugs,
    disclaimer:
      "Le informazioni fornite hanno scopo orientativo e non sostituiscono il parere di un medico veterinario. Consulta sempre un professionista per la salute del tuo animale.",
  };
}

// ── Generate all pages ──
export function generateAllServiceAnimalPages(): Record<string, ServiceAnimalPage> {
  // First pass: collect all valid slugs
  const allValidSlugs = new Set<string>();
  for (const animal of animalProfiles) {
    for (const template of serviceTemplates) {
      if (animal.applicableServices.includes(template.slugPrefix)) {
        allValidSlugs.add(`${template.slugPrefix}-${animal.id}`);
      }
    }
  }

  // Second pass: generate pages with validated related links
  const pages: Record<string, ServiceAnimalPage> = {};
  for (const animal of animalProfiles) {
    for (const template of serviceTemplates) {
      if (animal.applicableServices.includes(template.slugPrefix)) {
        const page = generateServiceAnimalPage(template, animal, allValidSlugs);
        pages[page.slug] = page;
      }
    }
  }

  return pages;
}

// Pre-generated for import
export const generatedServiceAnimalPages = generateAllServiceAnimalPages();
